import style from "./index.module.scss"
import template from './index.html'
import {
  select,
  timeParse,
  scaleTime,
  min,
  max,
  scaleLinear,
  line as d3Line,
  curveCatmullRom,
  axisBottom,
  axisLeft,
} from "d3"
import {simpleTheDate, handleTooltip} from "../../utils/util"

export default class Line extends HTMLElement {
  constructor() {
    super();
    const shadowRoot = this.attachShadow({ mode: 'open' });
    const sheet = new CSSStyleSheet();
    sheet.replaceSync(style);
    shadowRoot.adoptedStyleSheets = [sheet];
    shadowRoot.innerHTML = template
  }
  static get observedAttributes() {
    return [];
  }
  attributeChangedCallback(name, oldValue, newValue) {
    this.render()
  }

  willLoad = () => {
    this.rootEle = this.shadowRoot?.querySelector(".root")
  }
  connectedCallback() {
    this.classList.add("hydrated")
    handleTooltip(this)
    setTimeout(() => {
      this.willLoad()
      this.render()
      this.addEventListener("mouseout", e => {
        this.tooltip && (this.tooltip.style.display = "none")
      })
      window.addEventListener("resize", e => {
        this.render()
      })
    })
  }
  disconnectedCallback() {
  }

  render = () => {
    const parent = this.closest("div")
    if (!parent) return
    if (!this.shadowRoot) return
    const { width: rectW, height: reactH } = parent.getBoundingClientRect()
    if (!this.rootEle || rectW === 0) return
    this.rootEle.innerHTML = ""
    const lineChartData = this.data || [
      {
        currency: "USD",
        values: [
          {
            date: "2023/01/01",
            views: 230
          },
          {
            date: "2023/02/01",
            views: 269
          },
          {
            date: "2023/03/01",
            views: 234
          },
          {
            date: "2023/04/01",
            views: 282
          },
          {
            date: "2023/05/01",
            views: 231
          },
          {
            date: "2023/06/01",
            views: 240
          },
          {
            date: "2023/07/01",
            views: 200
          },
          {
            date: "2023/08/01",
            views: 320
          },
          {
            date: "2023/09/01",
            views: 253
          },
          {
            date: "2023/10/01",
            views: 264
          },
          {
            date: "2023/11/01",
            views: 272
          },
          {
            date: "2023/12/01",
            views: 290
          }
        ]
      }
    ];

    const margin = {
      top: 30,
      bottom: 20,
      left: 50,
      right: 30
    };

    const width = rectW - margin.left - margin.right;
    const height = 300 - margin.top - margin.bottom;

    const createGradient = select => {
      const gradient = select
        .select('defs')
        .append('linearGradient')
        .attr('id', 'gradient')
        .attr('x1', '0%')
        .attr('y1', '100%')
        .attr('x2', '0%')
        .attr('y2', '0%');

      gradient
        .append('stop')
        .attr('offset', '0%')
        .attr('style', 'stop-color:#777dcf;stop-opacity:0.05');

      gradient
        .append('stop')
        .attr('offset', '100%')
        .attr('style', 'stop-color:#777dcf;stop-opacity:.5');
    }

    const createGlowFilter = select => {
      const filter = select
        .select('defs')
        .append('filter')
        .attr('id', 'glow')

      filter
        .append('feGaussianBlur')
        .attr('stdDeviation', '4')
        .attr('result', 'coloredBlur');

      const femerge = filter
        .append('feMerge');

      femerge
        .append('feMergeNode')
        .attr('in', 'coloredBlur');
      femerge
        .append('feMergeNode')
        .attr('in', 'SourceGraphic');
    }

    const svg = select(this.rootEle).append("svg")
      .attr("width", width + margin.left + margin.right)
      .attr("height", height + margin.top + margin.bottom)
      .append("g")
      .attr("transform",
        "translate(" + margin.left + "," + margin.top + ")");

    svg.append('defs');
    svg.call(createGradient);
    svg.call(createGlowFilter);

    const parseTime = timeParse('%Y/%m/%d');

    const parsedData = lineChartData?.map(company => ({
      ticker: company.ticker,
      values: company.values.map(val => ({
        views: val.views,
        date: parseTime(val.date)
      }))
    }));

    const xScale = scaleTime()
      .domain([
        min(parsedData, d => min(d.values, v => v.date)),
        max(parsedData, d => max(d.values, v => v.date))
      ])
      .range([0, width]);

    const yScale = scaleLinear()
      .domain([
        min(parsedData, d => min(d.values, v => v.views)),
        max(parsedData, d => max(d.values, v => v.views))
      ])
      .range([height, 0]);

    const line = d3Line()
      .x(d => xScale(d.date))
      .y(d => yScale(d.views))
      .curve(curveCatmullRom.alpha(0.5));

    this.renderYGridLine({ svg, height, width })

    this.renderArea({ svg, parsedData, line, height })

    this.renderLine({ svg, parsedData, line })

    this.renderDotCircle({ svg, height, xScale, width, yScale, parsedData })

    this.renderYAxis({ svg, yScale, parsedData })
  }
  renderArea = ({ svg, parsedData, line, height }) => {
    svg.selectAll('.line')
      .data(parsedData)
      .enter()
      .append('path')
      .attr('d', d => {
        const lineValues = line(d.values).slice(1);
        const splitedValues = lineValues.split(',');

        return `M0,${height},${lineValues},l0,${height - splitedValues[splitedValues.length - 1]}`
      })
      .style('fill', 'url(#gradient)')
  }
  renderLine = ({ svg, parsedData, line }) => {
    svg.selectAll('.line')
      .data(parsedData)
      .enter()
      .append('path')
      .attr('d', d => line(d.values))
      .attr('stroke-width', '2')
      .style('fill', 'none')
      .style('filter', 'url(#glow)')
      .attr('stroke', '#555ed1');
  }
  renderDotCircle = ({ svg, height, xScale, width, yScale, parsedData }) => {
    function setFade(selection, opacity) {
      selection.style('opacity', opacity);
    }

    const tick = svg
      .append('g')
      .attr("class", "tick-circle-group")
      .attr('transform', `translate(0, ${height})`)
      .call(axisBottom(xScale).tickSize(0))
      .call(d => d.select(".domain").remove())
      .selectAll('.tick')
      .call(d => d.select("text").remove())
      .style('transition', '.2s')

    // tick
    //   .selectAll('line')
    //     .attr('stroke-dasharray', `5, 5`)
    //     .attr('stroke', '#ccc')
    //     .attr('y2', `-${height}px`)

    tick
      .selectAll('rect')
      .data(parsedData).enter()
      .append('rect')
      .attr('width', `${(width / 12) + 10}px`)
      .attr('x', `-${width / 24 + 5}px`)
      .attr('y', `-${height}px`)
      .attr('height', `${height}px`)
      .style('cursor', 'pointer')
      .style('opacity', '0')
      .style('fill', '#777dcf')

    tick
      .append('circle')
      .attr('r', '8px')
      .style('opacity', '0')
      .style('fill', 'white')
      .style("filter", "drop-shadow(var(--popover-shadow))")
      .attr('cy', (x, i) => - height + yScale(parsedData[0].values[i].views))
      .call(yScale)

    tick
      .append('circle')
      .attr('r', '4px')
      .style('opacity', '0')
      .style('fill', '#555ed1')
      .attr('cy', (x, i) => - height + yScale(parsedData[0].values[i].views))
      .call(yScale)


      
    const self = this
    tick
      .on('mouseout', function (event, data) {
        setFade(select(event.target), 0)
        setFade(select(event.currentTarget).selectAll("circle"), 0)
        select(self.tooltip).style('opacity', 0)
        self.tooltip.style.display = "none"
      })
      .on('mouseover', function (event, data, i) {
        self.tooltip.style.display = "flex"
        select(self.tooltip)
          .transition()
          .duration(200)
          .style('opacity', 1)
        const dot = self.tooltip.querySelector(".dot")
        dot.style.background = "#555ed1"
        const text = self.tooltip.querySelector(".text")
        const date = simpleTheDate(data)
        const theOne = parsedData[0].values.find(d => {
         return  simpleTheDate(d.date) === date
        })
        text.innerHTML = `${date} - ${theOne.views} views`
        setFade(select(event.target), 0.2)
        setFade(select(event.currentTarget).selectAll("circle"), 1)
      })
      .on('mousemove', e => {
        select(self.tooltip)
          .style('left', (e.clientX + 10) + 'px')
          .style('top', (e.clientY + 10) + 'px')
      })
  }
  renderYGridLine = ({ svg, height, width }) => {
    svg.append("g")
      .attr("class", "y-grid")
      .call(axisLeft(
          scaleLinear()
            // .domain(
            //   [
            //     min(parsedData, d => min(d.values, v => v.views)),
            //     max(parsedData, d => max(d.values, v => v.views))
            //   ]
            // )
            .range([height, 0]))
        .ticks(4)
        .tickSize(-width)
        .tickPadding(100)
        // .tickValues([
        //   min(parsedData, d => min(d.values, v => v.views)),
        //   max(parsedData, d => max(d.values, v => v.views))
        // ])
        // .tickFormat(value => {
        //   return value
        // })
      )
      .call(g => g.selectAll(".tick line")
        .attr("class", "y-axis-grid")
        .attr("stroke-dasharray", "5")
        .attr("stroke", "var(--text-quaternary)")
      )
      .call(d => d.select(".domain").remove())
  }
  renderYAxis = ({ svg, yScale, parsedData }) => {
    const yAxisLeft = axisLeft(yScale)
      .tickSize(0)
      .tickPadding(10)
      .ticks(4)
      // .tickValues([
      //   min(parsedData, d => min(d.values, v => v.views)),
      //   max(parsedData, d => max(d.values, v => v.views))
      // ])
    svg.append("g")
      .attr("class", "y axis")
      .call(yAxisLeft)
      .call(d => d.select(".domain").remove())
  }
}
